INSERT INTO public.report (id, resident_id, author_id, period_start, period_end, recorded_days, stats_summary, source_notice_ids, tone, ai_generated_text, final_text, status, sent_at, read_at, created_at, updated_at, deleted_at) VALUES (11, 2, 2, '2026-05-25', '2026-05-31', 7, '{"meal": {"FULL": 3, "LITTLE": 0, "NORMAL": 4, "REFUSED": 0}, "mood": {"GOOD": 6, "NORMAL": 1, "ANXIOUS": 0}, "health": {"GOOD": 5, "NORMAL": 2, "NEEDS_OBSERVATION": 0}, "topPrograms": [{"count": 1, "title": "치매"}, {"count": 1, "title": "두뇌"}], "recordedDays": 7}', '[65, 68, 71, 74, 77, 80, 83]', E'POLITE', E'5월 넷째 주 복남 어르신은 맑은 날씨 속에 요양원 마당을 거닐며 꽃들을 심으시는 원예 프로젝트에 흙손을 더해주셨습니다. 🌸 기분 좋게 밥과 반찬을 섭취해 체력을 기르셨고, 음악에 맞춰 리듬을 맞추며 한 주를 흥겹게 수놓으셨습니다. 복용약 관리도 이상무입니다. 다음 한 주도 복되게 동행하겠습니다. ✨', E'5월 넷째 주 복남 어르신은 맑은 날씨 속에 요양원 마당을 거닐며 꽃들을 심으시는 원예 프로젝트에 흙손을 더해주셨습니다. 🌸 기분 좋게 밥과 반찬을 섭취해 체력을 기르셨고, 음악에 맞춰 리듬을 맞추며 한 주를 흥겹게 수놓으셨습니다. 복용약 관리도 이상무입니다. 다음 한 주도 복되게 동행하겠습니다. ✨', E'SENT', '2026-05-31 18:00:00+00:00', NULL, '2026-06-01 10:37:42.044692+00:00', '2026-06-01 10:37:42.044692+00:00', NULL);
INSERT INTO public.report (id, resident_id, author_id, period_start, period_end, recorded_days, stats_summary, source_notice_ids, tone, ai_generated_text, final_text, status, sent_at, read_at, created_at, updated_at, deleted_at) VALUES (12, 3, 2, '2026-05-25', '2026-05-31', 7, '{"meal": {"FULL": 0, "LITTLE": 4, "NORMAL": 3, "REFUSED": 0}, "mood": {"GOOD": 6, "NORMAL": 1, "ANXIOUS": 0}, "health": {"GOOD": 5, "NORMAL": 0, "NEEDS_OBSERVATION": 2}, "topPrograms": [{"count": 1, "title": "치매"}, {"count": 1, "title": "두뇌"}], "recordedDays": 7}', '[66, 69, 72, 75, 78, 81, 84]', E'POLITE', E'5월 마지막 주 정호 어르신은 무리한 활동 없이 침대 위에서 잔잔한 고전 음악을 편히 들으시며 스트레칭을 실천하셨습니다. 🎵 가래나 기침 등 호흡기 불안 증세도 전혀 확인되지 않아 가슴 편안히 한 주를 나셨습니다. 매일 오후 휠체어로 안전히 이동해 거실에서 티비를 바라보며 부드러운 휴식을 영위하셨습니다. 매일 안전하고 소중하게 정성을 쏟겠습니다. 🍀', E'5월 마지막 주 정호 어르신은 무리한 활동 없이 침대 위에서 잔잔한 고전 음악을 편히 들으시며 스트레칭을 실천하셨습니다. 🎵 가래나 기침 등 호흡기 불안 증세도 전혀 확인되지 않아 가슴 편안히 한 주를 나셨습니다. 매일 오후 휠체어로 안전히 이동해 거실에서 티비를 바라보며 부드러운 휴식을 영위하셨습니다. 매일 안전하고 소중하게 정성을 쏟겠습니다. 🍀', E'SENT', '2026-05-31 18:00:00+00:00', NULL, '2026-06-01 10:37:42.044692+00:00', '2026-06-01 10:37:42.044692+00:00', NULL);
INSERT INTO public.notice_board (id, facility_id, author_id, title, content, created_at, updated_at, deleted_at) VALUES (1, 1, 3, E'🌸 어버이날 감사 특별 행사 및 보호자 간접 참여 안내', E'안녕하세요, 행복요양원 보호자 여러분.\n\n5월 8일 어버이날을 맞이하여 원내 어르신들을 모시고 카네이션 달아드리기 및 특별 감사 드림 행사를 진행합니다.\n\n감염 예방을 위해 직접 방문이 어려우신 보호자님들을 위하여, 행사 당일 실시간 사진 및 비대면 화상 통화를 적극적으로 지원해 드릴 예정이오니 많은 관심과 신청 바랍니다.\n\n항상 어르신들을 부모님처럼 소중히 모시는 행복요양원이 되겠습니다.', '2026-05-04 09:00:00+00:00', '2026-05-04 09:00:00+00:00', NULL);
INSERT INTO public.notice_board (id, facility_id, author_id, title, content, created_at, updated_at, deleted_at) VALUES (2, 1, 3, E'🧹 5월 원내 전체 위생 소독 및 봄맞이 대청소 일정', E'안녕하십니까, 시설본부입니다.\n\n어르신들의 안전하고 쾌적한 생활 환경을 유지하기 위해 5월 10일(일요일) 13:00부터 17:00까지 원내 전체 특별 방역 및 생활실 대청소를 실시합니다.\n\n해당 시간 동안 어르신들은 별도로 마련된 안전 대기실에서 보호를 받으실 예정이며, 방역 작업 중에는 면회가 제한되오니 면회 일정을 잡으실 때 참고해 주시면 감사하겠습니다.', '2026-05-08 10:30:00+00:00', '2026-05-08 10:30:00+00:00', NULL);
INSERT INTO public.notice_board (id, facility_id, author_id, title, content, created_at, updated_at, deleted_at) VALUES (3, 1, 3, E'👕 어르신 하절기 의복 교체 및 소지품 정돈 요청', E'안녕하세요. 행복요양원 간호부입니다.\n\n최근 낮 기온이 크게 올라감에 따라 어르신들의 하복 의류 준비가 필요한 시기입니다. 보호자님들께서는 이번 주말 방문 시 어르신들이 입으실 수 있는 얇은 하복(반팔, 얇은 긴바지 등)을 3~4벌 준비해 주시어 담당 간호사에게 전달 부탁드립니다.\n\n더불어 보관 중이던 두꺼운 겨울철 의복은 위생 관리를 위해 가정으로 회수해 주시길 부탁드립니다.', '2026-05-13 11:00:00+00:00', '2026-05-13 11:00:00+00:00', NULL);
INSERT INTO public.notice_board (id, facility_id, author_id, title, content, created_at, updated_at, deleted_at) VALUES (4, 1, 3, E'🚒 2분기 정기 소방 합동 대피 안전 훈련 실시 안내', E'보호자님들께 알립니다.\n\n행복요양원은 재난 발생 시 어르신들의 신속하고 안전한 대피 조치를 위해 관할 소방서와 함께하는 합동 대피 훈련을 5월 20일(수요일) 오후 3시에 진행합니다.\n\n훈련 시 소방 경보음 및 사이렌 소리가 들릴 수 있으나 실제 상황이 아니오니 인근 지역 주민분들과 내방객분들께서는 당황하지 마시고 직원의 안내에 협조해 주시기를 바랍니다.', '2026-05-18 14:00:00+00:00', '2026-05-18 14:00:00+00:00', NULL);
INSERT INTO public.notice_board (id, facility_id, author_id, title, content, created_at, updated_at, deleted_at) VALUES (5, 1, 3, E'💻 2026년도 상반기 비대면 보호자 간담회 개최 공지', E'안녕하십니까, 행복요양원 원장입니다.\n\n요양원 운영 현황과 하반기 주요 프로그램 계획을 안내해 드리고 보호자님들의 고견을 수렴하기 위해 온라인 간담회를 개최합니다.\n\n- 일시: 2026년 5월 27일(수) 오후 7시 ~ 8시\n- 방법: Zoom 비대면 온라인 회의 (접속 링크는 개별 문자 전송)\n- 주요 내용: 시설 리노베이션 안내, 영양 관리 현황 보고, 질의응답\n\n바쁘시더라도 자리를 함께하시어 따뜻한 동행이 이어질 수 있기를 희망합니다.', '2026-05-22 15:30:00+00:00', '2026-05-22 15:30:00+00:00', NULL);
INSERT INTO public.notice_board (id, facility_id, author_id, title, content, created_at, updated_at, deleted_at) VALUES (6, 1, 3, E'📋 6월 식단표 및 가정통신문 정기 공유 안내', E'보호자 여러분 안녕하십니까.\n\n다가오는 6월 한 달 동안 어르신들의 영양 균형과 소화기능을 최우선으로 고려하여 맞춘 영양 식단표와 6월 요양원 주요 소식 및 가정통신문을 전달해 드립니다.\n\n제철 야채와 보양식 식단 구성 등 다가오는 더위에 어르신들의 기력이 떨어지지 않도록 철저히 대비하겠습니다. 세부 식단 파일은 첨부 캘린더나 식단 조회를 통해 실시간 확인하실 수 있습니다.', '2026-05-29 09:00:00+00:00', '2026-05-29 09:00:00+00:00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (1, 5, 1, 1, E'김순자 어르신 감기 증상 및 약 처방 관련 문의', E'안녕하세요. 최근 일교차가 커져서 아침저녁으로 방이 쌀쌀한 것 같습니다. 혹시 순자 어르신께서 감기 기운이나 기침을 하지는 않으시는지 조심스럽게 여쭤봅니다. 필요하다면 가정에서 상비약을 가지고 방문하겠습니다.', E'HEALTH', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.92, "ADMIN_AFFAIRS": 0.02}', E'SUCCESS', E'READ', 1, '2026-05-04 16:30:00+00:00', NULL, '2026-05-04 14:00:00+00:00', '2026-05-04 14:00:00+00:00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (2, 6, 2, 1, E'어버이날 주말 대면 면회 신청합니다', E'어버이날을 맞아 5월 9일 토요일 오후 2시경에 아버님 대면 면회를 신청하고 싶습니다. 참여 가능 인원은 총 3명(보호자 부부, 자녀 1명)입니다. 예약 확인 및 가능 여부를 답변해 주시면 감사하겠습니다.', E'VISIT', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.92, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', E'SUCCESS', E'READ', 2, '2026-05-06 11:00:00+00:00', NULL, '2026-05-06 09:30:00+00:00', '2026-05-06 09:30:00+00:00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (3, 7, 3, 1, E'박정호 어르신 식사 섭취 관련 건의사항', E'아버님께서 치아 통증이 있으신지 최근 밥을 절반만 드셨다는 알림장을 받았습니다. 식단 제공 시 반찬류나 고기류를 아주 잘게 다지거나 부드러운 형태로 제공해 주실 수 있으신가요? 부탁드리겠습니다.', E'MEAL', 0.92, '{"MEAL": 0.92, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', E'SUCCESS', E'READ', 1, '2026-05-11 14:20:00+00:00', NULL, '2026-05-11 10:15:00+00:00', '2026-05-11 10:15:00+00:00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (4, 5, 1, 1, E'5월 장기요양 본인부담금 청구서 및 영수증 재발급 요청', E'안녕하세요. 계좌이체 내역과 대조해 보고 싶은 영수증 내역이 있어 5월 청구 영수증을 메일로 받아보고 싶습니다. 이메일 주소는 boram@family.kr 입니다. 확인 부탁드립니다.', E'ADMIN_AFFAIRS', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.92}', E'SUCCESS', E'READ', 2, '2026-05-14 13:00:00+00:00', NULL, '2026-05-14 11:00:00+00:00', '2026-05-14 11:00:00+00:00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (5, 6, 2, 1, E'석가탄신일 연휴 비대면 화상면회 희망', E'석가탄신일인 5월 24일에 가족들이 직접 갈 수가 없어서요. 영상통화로라도 아버님 얼굴을 뵙고 인사를 나누고 싶습니다. 일요일 오후 3시~4시 사이에 10분 정도 연결 가능할지 문의합니다.', E'VISIT', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.92, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', E'SUCCESS', E'READ', 2, '2026-05-20 18:00:00+00:00', NULL, '2026-05-20 16:20:00+00:00', '2026-05-20 16:20:00+00:00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (6, 7, 3, 1, E'박정호 어르신 정기 외래 진료 동행 안내 건', E'다음 주 목요일인 5월 28일에 서울대학병원 비뇨기과 예약이 있어 외출해야 합니다. 사설 구급차는 예약해 두었으며, 당일 오전 9시 30분에 모시러 갈 예정입니다. 외출 준비 및 차트 서류 챙기기 부탁드립니다.', E'HEALTH', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.92, "ADMIN_AFFAIRS": 0.02}', E'SUCCESS', E'READ', 1, '2026-05-22 11:30:00+00:00', NULL, '2026-05-22 10:00:00+00:00', '2026-05-22 10:00:00+00:00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (7, 5, 1, 1, E'김순자 어르신 개인 당뇨 간식 제재 요청', E'최근 요양원 프로그램에서 빵과 과자가 간식으로 나오는 것을 어르신께서 너무 기분 좋게 드셨다는 소식을 보았습니다. 당뇨를 앓고 계셔 혈당 급상승 우려가 있습니다. 탄수화물류 간식 섭취 비중을 줄여주실 수 있는지요.', E'MEAL', 0.92, '{"MEAL": 0.92, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', E'SUCCESS', E'READ', 1, '2026-05-25 16:10:00+00:00', NULL, '2026-05-25 14:45:00+00:00', '2026-05-25 14:45:00+00:00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (8, 6, 2, 1, E'주중 퇴근 후 야간 면회(19시 이후) 규정 문의', E'주말에는 급한 해외 출장이 잡혀 방문하기 힘듭니다. 혹시 평일 퇴근 후 19시경에 짧게 면회하는 것이 요양원 내부 규정상 허용되는지 여쭤보고 싶습니다. 불가피한 상황이라 답변 부탁드립니다.', E'VISIT', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.92, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', E'SUCCESS', E'UNREAD', NULL, NULL, NULL, '2026-05-27 18:00:00+00:00', '2026-05-27 18:00:00+00:00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (9, 5, 1, 1, E'순자 어르신 세탁물(카디건) 분실 확인 건', E'가족들이 지난주 사드렸던 진한 핑크색 꽃무늬 봄 카디건이 세탁실에서 섞였는지 장롱에 보이지 않는다고 하시네요. 세탁실 바구니나 다른 어르신 옷장으로 잘못 가지 않았는지 한 번만 수색해 봐주세요. 감사합니다.', E'OTHER', 0.92, '{"MEAL": 0.02, "OTHER": 0.92, "VISIT": 0.02, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', E'SUCCESS', E'UNREAD', NULL, NULL, NULL, '2026-05-28 10:00:00+00:00', '2026-05-28 10:00:00+00:00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (10, 7, 3, 1, E'욕창 예방 전용 에어 매트리스 설치 여부', E'아버님께서 와상 상태로 침상 생활 비중이 아주 높다 보니 피부 욕창이 크게 염려됩니다. 필요시 개인용 욕창 매트리스를 구매해서 병실 침대에 설치하는 것이 반입 및 전기 사용 허용 규정에 어긋나지 않는지 알려주십시오.', E'HEALTH', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.92, "ADMIN_AFFAIRS": 0.02}', E'SUCCESS', E'UNREAD', NULL, NULL, NULL, '2026-05-29 13:00:00+00:00', '2026-05-29 13:00:00+00:00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (11, 6, 2, 1, E'6월 둘째 주 주말 예약 면회 신청', E'6월 13일 토요일 오전 11시에 대면 면회 2명 신청하고 싶습니다. 시간이 많이 남아있지만 인원이 마감되기 전에 미리 등록하고자 하오니 예약 조치 후 확인 부탁드립니다.', E'VISIT', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.92, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', E'SUCCESS', E'UNREAD', NULL, NULL, NULL, '2026-05-30 10:00:00+00:00', '2026-05-30 10:00:00+00:00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (12, 5, 1, 1, E'장기요양 세액공제 증명원 팩스 전송 요청', E'직장 연말정산 보정 기간이라 요양원 납부 확인 내역이 필요해졌습니다. 회사 팩스 번호인 02-9999-8888 번으로 증명원을 한 부만 팩스 송부해 주실 수 있을까요? 늦어도 다음 주 월요일까지 부탁드립니다.', E'ADMIN_AFFAIRS', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.92}', E'SUCCESS', E'UNREAD', NULL, NULL, NULL, '2026-06-01 09:30:00+00:00', '2026-06-01 09:30:00+00:00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (13, 5, 1, 1, E'어르신 간식 및 음료 제공 관련 문의', E'최근 요양원 간식 제공 내역을 보니 어르신께서 단 음료를 자주 드시는 것으로 확인되었습니다. 혈압과 혈당 관리가 필요한 상태여서 음료 섭취가 다소 걱정됩니다. 가능하다면 당 함량이 낮은 음료나 물, 차 위주로 제공해 주실 수 있는지 문의드립니다.', E'MEAL', 0.7, '{"MEAL": 0.7, "OTHER": 0.0, "VISIT": 0.0, "HEALTH": 0.3, "ADMIN_AFFAIRS": 0.0}', E'SUCCESS', E'UNREAD', NULL, NULL, NULL, '2026-06-01 11:27:15.150087+00:00', '2026-06-01 11:27:15.150087+00:00', NULL);
