INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (88, 4, 1, NULL, 1, '{"health": "GOOD", "mood": "NORMAL", "meal": "LITTLE", "medication": "DONE"}', '[]', E'무릎 찜질 치료 받으셨습니다. 오후 노래교실 참여하셔서 즐거워하셨습니다. 식사 잘 드셨습니다.', 'POLITE', '[{"index": 0, "label": "A", "text": "보호자님 안녕하세요! 🎶 오늘 영자 어르신께서는 오전에 무릎 관절 통증 완화를 위한 온열 찜질 치료를 받으시며 편안한 시간을 가지셨습니다. 오후에는 노래교실에 참여하셔서 좋아하시는 옛 노래를 부르며 밝게 웃으셨습니다. 😄 식사도 반찬을 골고루 드시며 맛있게 마치셨습니다. 🌸"}, {"index": 1, "label": "B", "text": "안녕하세요 보호자님. 💖 영자 어르신은 오늘 무릎 온열 찜질 케어를 받으시고 오후에 노래교실 프로그램에 활기차게 참여하셨습니다. 🎵 기분이 좋으셔서 노래를 따라 부르시며 즐거운 시간을 보내셨고 식사도 순조롭게 마치셨습니다."}, {"index": 2, "label": "C", "text": "영자 어르신 소식입니다. 🌟 오늘 어르신은 온열 찜질 치료로 관절 통증을 완화하시고 노래 교실에서 밝은 시간을 보내셨습니다. 식사도 잘 드셨습니다. ✨"}]', 0, FALSE, E'보호자님 안녕하세요! 🎶 오늘 영자 어르신께서는 오전에 무릎 관절 통증 완화를 위한 온열 찜질 치료를 받으시며 편안한 시간을 가지셨습니다. 오후에는 노래교실에 참여하셔서 좋아하시는 옛 노래를 부르며 밝게 웃으셨습니다. 😄 식사도 반찬을 골고루 드시며 맛있게 마치셨습니다. 🌸', 'SENT', FALSE, '2026-05-25 17:00:00+00:00', '2026-05-25 20:00:00+00:00', '2026-05-25 09:00:00+00:00', '2026-05-25 09:00:00+00:00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (89, 4, 1, NULL, 1, '{"health": "GOOD", "mood": "GOOD", "meal": "NORMAL", "medication": "DONE"}', '[]', E'무릎 통증 조금 있으셨지만 의자 앉아 인지치료 잘 참여하셨습니다. 식사 잘 하셨습니다.', 'POLITE', '[{"index": 0, "label": "A", "text": "보호자님 안녕하세요. 😊 오늘 영자 어르신께서는 무릎 관절이 다소 불편하셨지만 의자에 편안히 앉으셔서 인지치료 활동에 성실히 참여해 주셨습니다. 🧩 식사도 따뜻한 국물과 함께 맛있게 드셨고, 투약도 잘 완료하셨습니다. 편안한 저녁 되세요. 🌸"}, {"index": 1, "label": "B", "text": "안녕하세요 보호자님! 😊 영자 어르신은 오늘 무릎 관절 통증이 약간 있으셨음에도 자리에 앉아 즐겁게 인지 프로그램에 참여하셨습니다. 🌟 식사와 복약 모두 원활히 진행되었으며 특이사항 없이 하루를 잘 마무리하셨습니다. 💖"}, {"index": 2, "label": "C", "text": "영자 어르신 보호자님께 안부 전합니다. 🌷 오늘 어르신은 무릎 상태를 살피며 의자 활동 위주로 프로그램에 참여하셨습니다. 식사도 잘 하시고 안정적인 하루를 보내셨습니다. ✨"}]', 0, FALSE, E'보호자님 안녕하세요. 😊 오늘 영자 어르신께서는 무릎 관절이 다소 불편하셨지만 의자에 편안히 앉으셔서 인지치료 활동에 성실히 참여해 주셨습니다. 🧩 식사도 따뜻한 국물과 함께 맛있게 드셨고, 투약도 잘 완료하셨습니다. 편안한 저녁 되세요. 🌸', 'SENT', FALSE, '2026-05-26 17:00:00+00:00', '2026-05-26 20:00:00+00:00', '2026-05-26 09:00:00+00:00', '2026-05-26 09:00:00+00:00', NULL, 'ko');
