INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (94, 4, 1, NULL, 1, '{"health": "GOOD", "mood": "GOOD", "meal": "LITTLE", "medication": "DONE"}', '[]', E'무릎 찜질 치료 받으셨습니다. 오후 노래교실 참여하셔서 즐거워하셨습니다. 식사 잘 드셨습니다.', 'POLITE', '[{"index": 0, "label": "A", "text": "보호자님 안녕하세요! 🎶 오늘 영자 어르신께서는 오전에 무릎 관절 통증 완화를 위한 온열 찜질 치료를 받으시며 편안한 시간을 가지셨습니다. 오후에는 노래교실에 참여하셔서 좋아하시는 옛 노래를 부르며 밝게 웃으셨습니다. 😄 식사도 반찬을 골고루 드시며 맛있게 마치셨습니다. 🌸"}, {"index": 1, "label": "B", "text": "안녕하세요 보호자님. 💖 영자 어르신은 오늘 무릎 온열 찜질 케어를 받으시고 오후에 노래교실 프로그램에 활기차게 참여하셨습니다. 🎵 기분이 좋으셔서 노래를 따라 부르시며 즐거운 시간을 보내셨고 식사도 순조롭게 마치셨습니다."}, {"index": 2, "label": "C", "text": "영자 어르신 소식입니다. 🌟 오늘 어르신은 온열 찜질 치료로 관절 통증을 완화하시고 노래 교실에서 밝은 시간을 보내셨습니다. 식사도 잘 드셨습니다. ✨"}]', 0, FALSE, E'보호자님 안녕하세요! 🎶 오늘 영자 어르신께서는 오전에 무릎 관절 통증 완화를 위한 온열 찜질 치료를 받으시며 편안한 시간을 가지셨습니다. 오후에는 노래교실에 참여하셔서 좋아하시는 옛 노래를 부르며 밝게 웃으셨습니다. 😄 식사도 반찬을 골고루 드시며 맛있게 마치셨습니다. 🌸', 'SENT', FALSE, '2026-05-31 17:00:00+00:00', NULL, '2026-05-31 09:00:00+00:00', '2026-05-31 09:00:00+00:00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (95, 5, 1, NULL, 1, '{"health": "GOOD", "mood": "NORMAL", "meal": "LITTLE", "medication": "DONE"}', '[]', E'사진 보며 옛이야기 나누는 회상 프로그램 즐기셨습니다. 가끔 혼돈 있으셨지만 안정적이었습니다. 식사 잘 하셨습니다.', 'POLITE', '[{"index": 0, "label": "A", "text": "보호자님 안녕하세요. 📸 오늘 달수 어르신께서는 옛 사진을 보며 추억을 나누는 회상 요법 프로그램에 즐겁게 참여하셨습니다. 가끔 날짜나 장소에 대한 혼돈이 있으셨지만 요양사가 곁에서 차분히 안내하며 안정적으로 프로그램을 마치셨습니다. 😊 식사도 오늘은 잘 드셨습니다. 🌸"}, {"index": 1, "label": "B", "text": "안녕하세요 보호자님. 달수 어르신은 사진 회상 프로그램에서 좋아하는 옛 노래와 사진을 보며 밝게 웃으셨습니다. 💖 전반적으로 안정적인 하루를 보내셨고 식사도 잘 마치셨습니다."}, {"index": 2, "label": "C", "text": "달수 어르신 소식입니다. 🌟 오늘 어르신은 회상 프로그램을 통해 즐거운 시간을 보내셨으며 안정적인 상태로 하루를 마무리하셨습니다. ✨"}]', 0, FALSE, E'보호자님 안녕하세요. 📸 오늘 달수 어르신께서는 옛 사진을 보며 추억을 나누는 회상 요법 프로그램에 즐겁게 참여하셨습니다. 가끔 날짜나 장소에 대한 혼돈이 있으셨지만 요양사가 곁에서 차분히 안내하며 안정적으로 프로그램을 마치셨습니다. 😊 식사도 오늘은 잘 드셨습니다. 🌸', 'SENT', FALSE, '2026-05-25 17:00:00+00:00', '2026-05-25 20:00:00+00:00', '2026-05-25 09:00:00+00:00', '2026-05-25 09:00:00+00:00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (96, 5, 1, NULL, 1, '{"health": "GOOD", "mood": "GOOD", "meal": "NORMAL", "medication": "DONE"}', '[]', E'오전에 이름·날짜 회상 훈련 잘 따라 하셨습니다. 오후 산책 대신 실내 체조 참여하셨습니다. 식사 보통이었습니다.', 'POLITE', '[{"index": 0, "label": "A", "text": "보호자님 안녕하세요. 🌿 오늘 달수 어르신께서는 오전 인지 회상 훈련 시간에 이름 카드와 날짜 맞추기 활동을 차분하게 잘 따라 주셨습니다. 🧩 오후에는 실내 체조로 가볍게 몸을 풀며 혈액 순환을 도왔습니다. 식사는 보통 양으로 드셨고 투약도 빠짐없이 완료하셨습니다. 😊"}, {"index": 1, "label": "B", "text": "안녕하세요 보호자님! 달수 어르신은 오늘 기억력 향상 훈련에 차분히 참여하셨고 실내에서 즐거운 체조 시간을 가지셨습니다. 🌟 식사와 복약도 잘 마치셨습니다. 💖"}, {"index": 2, "label": "C", "text": "달수 어르신 보호자님께 안부 드립니다. 🍀 오늘 어르신은 인지 훈련과 실내 활동을 통해 즐거운 하루를 보내셨습니다. 식사도 잘 하셨습니다. ✨"}]', 0, FALSE, E'보호자님 안녕하세요. 🌿 오늘 달수 어르신께서는 오전 인지 회상 훈련 시간에 이름 카드와 날짜 맞추기 활동을 차분하게 잘 따라 주셨습니다. 🧩 오후에는 실내 체조로 가볍게 몸을 풀며 혈액 순환을 도왔습니다. 식사는 보통 양으로 드셨고 투약도 빠짐없이 완료하셨습니다. 😊', 'SENT', FALSE, '2026-05-26 17:00:00+00:00', '2026-05-26 20:00:00+00:00', '2026-05-26 09:00:00+00:00', '2026-05-26 09:00:00+00:00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (97, 5, 1, NULL, 1, '{"health": "GOOD", "mood": "GOOD", "meal": "FULL", "medication": "DONE"}', '[]', E'사진 보며 옛이야기 나누는 회상 프로그램 즐기셨습니다. 가끔 혼돈 있으셨지만 안정적이었습니다. 식사 잘 하셨습니다.', 'POLITE', '[{"index": 0, "label": "A", "text": "보호자님 안녕하세요. 📸 오늘 달수 어르신께서는 옛 사진을 보며 추억을 나누는 회상 요법 프로그램에 즐겁게 참여하셨습니다. 가끔 날짜나 장소에 대한 혼돈이 있으셨지만 요양사가 곁에서 차분히 안내하며 안정적으로 프로그램을 마치셨습니다. 😊 식사도 오늘은 잘 드셨습니다. 🌸"}, {"index": 1, "label": "B", "text": "안녕하세요 보호자님. 달수 어르신은 사진 회상 프로그램에서 좋아하는 옛 노래와 사진을 보며 밝게 웃으셨습니다. 💖 전반적으로 안정적인 하루를 보내셨고 식사도 잘 마치셨습니다."}, {"index": 2, "label": "C", "text": "달수 어르신 소식입니다. 🌟 오늘 어르신은 회상 프로그램을 통해 즐거운 시간을 보내셨으며 안정적인 상태로 하루를 마무리하셨습니다. ✨"}]', 0, FALSE, E'보호자님 안녕하세요. 📸 오늘 달수 어르신께서는 옛 사진을 보며 추억을 나누는 회상 요법 프로그램에 즐겁게 참여하셨습니다. 가끔 날짜나 장소에 대한 혼돈이 있으셨지만 요양사가 곁에서 차분히 안내하며 안정적으로 프로그램을 마치셨습니다. 😊 식사도 오늘은 잘 드셨습니다. 🌸', 'SENT', FALSE, '2026-05-27 17:00:00+00:00', '2026-05-27 20:00:00+00:00', '2026-05-27 09:00:00+00:00', '2026-05-27 09:00:00+00:00', NULL, 'ko');
