INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (102, 6, 2, NULL, 1, '{"health": "GOOD", "mood": "NORMAL", "meal": "LITTLE", "medication": "DONE"}', '[]', E'노래교실에서 손뼉 치며 신나게 참여하셨습니다. 식사 잘 하셨습니다. 오후 컨디션 양호하셨습니다.', 'POLITE', '[{"index": 0, "label": "A", "text": "보호자님 안녕하세요! 🎵 오늘 말례 어르신께서는 청력 보조 기기를 착용하시고 노래 교실 시간에 즐겨 듣는 민요에 맞춰 손뼉을 치시며 신나게 참여하셨습니다. 😄 오후에도 컨디션이 양호하셨으며 식사도 국물 위주로 잘 드셨습니다. 🌸"}, {"index": 1, "label": "B", "text": "안녕하세요 보호자님. 😊 말례 어르신은 오늘 노래 교실에서 리듬에 맞춰 박자를 즐기시며 활기찬 시간을 보내셨습니다. 🎶 식사도 잘 마치셨습니다. 💖"}, {"index": 2, "label": "C", "text": "말례 어르신 소식입니다. 🌟 오늘 어르신은 노래 교실에서 즐거운 시간을 보내셨고 식사도 잘 하셨습니다. ✨"}]', 0, FALSE, E'보호자님 안녕하세요! 🎵 오늘 말례 어르신께서는 청력 보조 기기를 착용하시고 노래 교실 시간에 즐겨 듣는 민요에 맞춰 손뼉을 치시며 신나게 참여하셨습니다. 😄 오후에도 컨디션이 양호하셨으며 식사도 국물 위주로 잘 드셨습니다. 🌸', 'SENT', FALSE, '2026-05-25 17:00:00+00:00', '2026-05-25 20:00:00+00:00', '2026-05-25 09:00:00+00:00', '2026-05-25 09:00:00+00:00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (103, 6, 2, NULL, 1, '{"health": "GOOD", "mood": "GOOD", "meal": "NORMAL", "medication": "DONE"}', '[]', E'보청기 착용 상태 확인하고 큰 목소리로 소통했습니다. 오후 미술치료 참여하셨습니다. 식사 잘 하셨습니다.', 'POLITE', '[{"index": 0, "label": "A", "text": "보호자님 안녕하세요. 🎨 오늘 말례 어르신께서는 보청기를 편안하게 착용하시고 요양사와 큰 목소리로 즐겁게 소통하셨습니다. 오후에는 미술 치료 시간에 색종이로 작품을 만드시며 즐거운 표정을 지어주셨습니다. 🌸 식사도 오늘은 처음부터 끝까지 잘 드셨고 투약도 완료하셨습니다. 😊"}, {"index": 1, "label": "B", "text": "안녕하세요 보호자님! 말례 어르신은 오늘 보청기를 잘 착용하시고 미술 치료에 활발히 참여하셨습니다. 🎨 식사와 투약도 잘 마치셨습니다. 💖"}, {"index": 2, "label": "C", "text": "말례 어르신 보호자님께 안부 전합니다. 🌷 오늘 어르신은 보청기를 착용하시고 편안하게 소통하시며 즐거운 미술 활동에 참여하셨습니다. ✨"}]', 0, FALSE, E'보호자님 안녕하세요. 🎨 오늘 말례 어르신께서는 보청기를 편안하게 착용하시고 요양사와 큰 목소리로 즐겁게 소통하셨습니다. 오후에는 미술 치료 시간에 색종이로 작품을 만드시며 즐거운 표정을 지어주셨습니다. 🌸 식사도 오늘은 처음부터 끝까지 잘 드셨고 투약도 완료하셨습니다. 😊', 'SENT', FALSE, '2026-05-26 17:00:00+00:00', '2026-05-26 20:00:00+00:00', '2026-05-26 09:00:00+00:00', '2026-05-26 09:00:00+00:00', NULL, 'ko');
