INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (109, 7, 2, NULL, 1, '{"health": "GOOD", "mood": "NORMAL", "meal": "LITTLE", "medication": "DONE"}', '[]', E'오늘도 활발하게 프로그램 참여하셨습니다. 친구 어르신들과 대화 많이 하셨고 식사 아주 잘 하셨습니다.', 'POLITE', '[{"index": 0, "label": "A", "text": "보호자님 안녕하세요! 😊 오늘 금자 어르신께서는 오전 프로그램부터 오후 활동까지 에너지 넘치게 참여하셨습니다. 다른 어르신들과 즐겁게 대화를 나누시며 분위기를 밝혀 주셨어요. 🌟 식사는 오늘 특히 맛있게 드셔서 반찬을 더 요청하실 정도였습니다. 건강한 하루를 보내셨습니다. 💖"}, {"index": 1, "label": "B", "text": "안녕하세요 보호자님. 금자 어르신은 오늘도 활기차게 하루를 보내셨습니다. 🌸 어르신들과 정다운 이야기를 나누시며 식사도 아주 잘 드셨습니다. 😄"}, {"index": 2, "label": "C", "text": "금자 어르신 소식입니다. ✨ 오늘 어르신은 활발한 하루를 보내셨고 식사도 아주 잘 하셨습니다. 건강 상태도 양호합니다. 🌟"}]', 0, FALSE, E'보호자님 안녕하세요! 😊 오늘 금자 어르신께서는 오전 프로그램부터 오후 활동까지 에너지 넘치게 참여하셨습니다. 다른 어르신들과 즐겁게 대화를 나누시며 분위기를 밝혀 주셨어요. 🌟 식사는 오늘 특히 맛있게 드셔서 반찬을 더 요청하실 정도였습니다. 건강한 하루를 보내셨습니다. 💖', 'SENT', FALSE, '2026-05-25 17:00:00+00:00', '2026-05-25 20:00:00+00:00', '2026-05-25 09:00:00+00:00', '2026-05-25 09:00:00+00:00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (110, 7, 2, NULL, 1, '{"health": "GOOD", "mood": "GOOD", "meal": "NORMAL", "medication": "DONE"}', '[]', E'오전 인지치료 참여하셨고 손 뜨개질도 하셨습니다. 식사 잘 하셨습니다.', 'POLITE', '[{"index": 0, "label": "A", "text": "보호자님 안녕하세요. 🧶 오늘 금자 어르신께서는 오전 인지치료 시간에 밝은 표정으로 집중하여 참여해 주셨습니다. 활동 후에는 좋아하시는 손 뜨개질을 하시며 여유로운 오후를 보내셨어요. 🌸 식사는 오늘도 골고루 맛있게 드셨고 건강하게 하루를 마무리하셨습니다. 😊"}, {"index": 1, "label": "B", "text": "안녕하세요 보호자님! 금자 어르신은 오늘 인지치료와 뜨개질 활동으로 즐겁고 알찬 하루를 보내셨습니다. 🌟 식사도 잘 드셨고 전반적으로 좋은 상태입니다. 💖"}, {"index": 2, "label": "C", "text": "금자 어르신 보호자님께 안부 드립니다. 😊 오늘 어르신은 인지치료와 손작업 활동으로 건강한 하루를 보내셨습니다. 식사도 잘 하셨습니다. 🌸"}]', 0, FALSE, E'보호자님 안녕하세요. 🧶 오늘 금자 어르신께서는 오전 인지치료 시간에 밝은 표정으로 집중하여 참여해 주셨습니다. 활동 후에는 좋아하시는 손 뜨개질을 하시며 여유로운 오후를 보내셨어요. 🌸 식사는 오늘도 골고루 맛있게 드셨고 건강하게 하루를 마무리하셨습니다. 😊', 'SENT', FALSE, '2026-05-26 17:00:00+00:00', '2026-05-26 20:00:00+00:00', '2026-05-26 09:00:00+00:00', '2026-05-26 09:00:00+00:00', NULL, 'ko');
