INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (116, 8, 1, NULL, 1, '{"health": "NORMAL", "mood": "GOOD", "meal": "DONE", "medication": "DONE"}', '[]', E'체온 정상, 혈압 안정적. 위루관 주입 완료. 음악 치료 CD 듣고 좋아하셨습니다.', 'POLITE', '[{"index": 0, "label": "A", "text": "보호자님 안녕하세요. 🎵 오늘 상철 어르신의 체온과 혈압이 정상 범위로 안정적으로 유지되었습니다. 위루관 영양 주입도 이상 없이 완료되었고, 오후에는 좋아하시는 옛 가요 CD를 틀어드리자 눈을 감고 조용히 음악을 감상하시며 편안한 표정을 지어주셨습니다. 😌"}, {"index": 1, "label": "B", "text": "안녕하세요 보호자님. 상철 어르신은 오늘 활력 징후가 안정적이었고 위루관 주입도 완료되었습니다. 🌟 음악 감상으로 편안한 오후를 보내셨습니다. 💖"}, {"index": 2, "label": "C", "text": "상철 어르신 소식입니다. 🌿 오늘 어르신은 건강 상태가 양호하였고 음악 치료로 평온한 시간을 보내셨습니다. 위루관 케어도 순조로웠습니다. ✨"}]', 0, FALSE, E'보호자님 안녕하세요. 🎵 오늘 상철 어르신의 체온과 혈압이 정상 범위로 안정적으로 유지되었습니다. 위루관 영양 주입도 이상 없이 완료되었고, 오후에는 좋아하시는 옛 가요 CD를 틀어드리자 눈을 감고 조용히 음악을 감상하시며 편안한 표정을 지어주셨습니다. 😌', 'SENT', FALSE, '2026-05-25 17:00:00+00:00', '2026-05-25 20:00:00+00:00', '2026-05-25 09:00:00+00:00', '2026-05-25 09:00:00+00:00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (117, 8, 1, NULL, 1, '{"health": "NORMAL", "mood": "GOOD", "meal": "DONE", "medication": "DONE"}', '[]', E'위루관 영양 주입 순조로웠습니다. 침상 관절 스트레칭 받으셨고 욕창 예방 체위 변경 시행했습니다.', 'POLITE', '[{"index": 0, "label": "A", "text": "보호자님 안녕하세요. 🌿 오늘 상철 어르신께서는 위루관을 통한 영양 주입이 순조롭게 진행되었습니다. 오전에는 침상에서 굳지 않도록 부드러운 관절 스트레칭을 편안하게 받으셨고, 욕창 예방을 위한 정기적인 체위 변경도 꼼꼼히 시행하였습니다. 피부 상태 모두 양호하게 유지되고 있습니다. 😊"}, {"index": 1, "label": "B", "text": "안녕하세요 보호자님. 상철 어르신은 오늘 위루관 영양 주입이 원활히 완료되었고 침상 스트레칭 케어도 잘 받으셨습니다. 🌟 체위 변경을 통해 피부 상태를 꼼꼼히 관리하였습니다. 💖"}, {"index": 2, "label": "C", "text": "상철 어르신 보호자님께 안부 드립니다. 🍀 오늘 어르신은 위루관 영양 주입과 침상 케어가 모두 원활히 진행되었습니다. 피부 및 전신 상태 양호합니다. ✨"}]', 0, FALSE, E'보호자님 안녕하세요. 🌿 오늘 상철 어르신께서는 위루관을 통한 영양 주입이 순조롭게 진행되었습니다. 오전에는 침상에서 굳지 않도록 부드러운 관절 스트레칭을 편안하게 받으셨고, 욕창 예방을 위한 정기적인 체위 변경도 꼼꼼히 시행하였습니다. 피부 상태 모두 양호하게 유지되고 있습니다. 😊', 'SENT', FALSE, '2026-05-26 17:00:00+00:00', '2026-05-26 20:00:00+00:00', '2026-05-26 09:00:00+00:00', '2026-05-26 09:00:00+00:00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (118, 8, 1, NULL, 1, '{"health": "NORMAL", "mood": "NORMAL", "meal": "DONE", "medication": "DONE"}', '[]', E'체온 정상, 혈압 안정적. 위루관 주입 완료. 음악 치료 CD 듣고 좋아하셨습니다.', 'POLITE', '[{"index": 0, "label": "A", "text": "보호자님 안녕하세요. 🎵 오늘 상철 어르신의 체온과 혈압이 정상 범위로 안정적으로 유지되었습니다. 위루관 영양 주입도 이상 없이 완료되었고, 오후에는 좋아하시는 옛 가요 CD를 틀어드리자 눈을 감고 조용히 음악을 감상하시며 편안한 표정을 지어주셨습니다. 😌"}, {"index": 1, "label": "B", "text": "안녕하세요 보호자님. 상철 어르신은 오늘 활력 징후가 안정적이었고 위루관 주입도 완료되었습니다. 🌟 음악 감상으로 편안한 오후를 보내셨습니다. 💖"}, {"index": 2, "label": "C", "text": "상철 어르신 소식입니다. 🌿 오늘 어르신은 건강 상태가 양호하였고 음악 치료로 평온한 시간을 보내셨습니다. 위루관 케어도 순조로웠습니다. ✨"}]', 0, FALSE, E'보호자님 안녕하세요. 🎵 오늘 상철 어르신의 체온과 혈압이 정상 범위로 안정적으로 유지되었습니다. 위루관 영양 주입도 이상 없이 완료되었고, 오후에는 좋아하시는 옛 가요 CD를 틀어드리자 눈을 감고 조용히 음악을 감상하시며 편안한 표정을 지어주셨습니다. 😌', 'SENT', FALSE, '2026-05-27 17:00:00+00:00', '2026-05-27 20:00:00+00:00', '2026-05-27 09:00:00+00:00', '2026-05-27 09:00:00+00:00', NULL, 'ko');
