INSERT INTO public.album (id, facility_id, author_id, activity_date, title, description, photos, created_at, updated_at, deleted_at) VALUES (3, 1, 2, '2026-05-24 14:00:00', E'봄 원예 교실 🌱', E'허브와 작은 꽃 모종을 직접 심어보는 원예 활동을 진행했습니다. 흙냄새와 초록 식물을 가까이하며 어르신들이 환하게 웃으셨습니다.', '[]', '2026-05-24 18:00:00+00:00', '2026-05-24 18:00:00+00:00', NULL);
